 1	import * as React from 'react';
 2	import { getVMTemplateBaseName } from 'src/views/templates/utils/selectors';
 3	
 4	import VirtualMachineDescriptionItem from '@kubevirt-utils/components/VirtualMachineDescriptionItem/VirtualMachineDescriptionItem';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import { modelToGroupVersionKind, TemplateModel, V1Template } from '@kubevirt-utils/models';
 7	import { ResourceLink } from '@openshift-console/dynamic-plugin-sdk';
 8	import { Text } from '@patternfly/react-core';
 9	
10	type BaseTemplateProps = {
11	  template: V1Template;
12	};
13	
14	const BaseTemplate: React.FC<BaseTemplateProps> = ({ template }) => {
15	  const { t } = useKubevirtTranslation();
16	  const baseTemplate = getVMTemplateBaseName(template);
17	
18	  return (
19	    <VirtualMachineDescriptionItem
20	      descriptionData={
21	        baseTemplate ? (
22	          <ResourceLink
23	            groupVersionKind={modelToGroupVersionKind(TemplateModel)}
24	            {...baseTemplate}
25	          />
26	        ) : (
27	          <Text className="text-muted">{t('Not available')}</Text>
28	        )
29	      }
30	      descriptionHeader={t('Base template')}
31	    />
32	  );
33	};
34	
35	export default BaseTemplate;

